const leads = $input.all()[0]?.json?.data || [];
const sent = $input.all()[1]?.json?.data || [];
const followup = $input.all()[2]?.json?.data || [];

const now = new Date();
const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());
const weekAgo = new Date(today - 7*24*60*60*1000);
const monthAgo = new Date(today - 30*24*60*60*1000);

const leadsToday = leads.filter(l => new Date(l.createdAt) >= today).length;
const leadsWeek = leads.filter(l => new Date(l.createdAt) >= weekAgo).length;
const leadsMonth = leads.filter(l => new Date(l.createdAt) >= monthAgo).length;

const sentToday = sent.filter(s => new Date(s.sentAt) >= today).length;
const sentWeek = sent.filter(s => new Date(s.sentAt) >= weekAgo).length;

const replied = leads.filter(l => l.status === 'replied' || l.status === 'interested').length;
const meetings = leads.filter(l => l.status === 'meeting' || l.status === 'booked').length;
const won = leads.filter(l => l.status === 'won' || l.status === 'converted').length;
const lost = leads.filter(l => l.status === 'lost' || l.status === 'not-interested').length;

const report = {
  generatedAt: now.toISOString(),
  period: {today: today.toISOString(), weekAgo: weekAgo.toISOString(), monthAgo: monthAgo.toISOString()},
  leads: {total: leads.length, today: leadsToday, week: leadsWeek, month: leadsMonth},
  outreach: {sentToday, sentWeek, totalSent: sent.length, followups: followup.length},
  responses: {replied, meetings, won, lost},
  conversionRate: leads.length > 0 ? Math.round((won / leads.length) * 100) : 0,
  replyRate: sent.length > 0 ? Math.round((replied / sent.length) * 100) : 0
};
return report;
